import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Switch } from "@/components/ui/switch";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { type User, type Warehouse } from "@shared/schema";
import { z } from "zod";

const userFormSchema = z.object({
  username: z.string().min(1, "El nombre de usuario es requerido"),
  firstName: z.string().min(1, "El nombre es requerido"),
  lastName: z.string().min(1, "El apellido es requerido"),
  email: z.string().email("Email inválido").optional().or(z.literal("")),
  role: z.enum(["user", "admin", "project_manager", "warehouse_operator"]),
  costCenter: z.string().optional(),
  isActive: z.boolean(),
  password: z.string().optional(),
});

type UserFormData = z.infer<typeof userFormSchema>;

interface UserFormProps {
  user?: User;
  onSuccess?: () => void;
  onCancel?: () => void;
}

export default function UserForm({ user, onSuccess, onCancel }: UserFormProps) {
  const { toast } = useToast();

  const { data: warehouses = [] } = useQuery<Warehouse[]>({
    queryKey: ["/api/warehouses"],
  });

  // Extraer centros de costo únicos
  const costCenters = warehouses
    .map(w => w.costCenter)
    .filter(Boolean)
    .reduce((unique: string[], center: string) => {
      return unique.includes(center) ? unique : [...unique, center];
    }, []);

  const form = useForm<UserFormData>({
    resolver: zodResolver(
      user 
        ? userFormSchema.extend({ password: z.string().optional() })
        : userFormSchema.extend({ password: z.string().min(1, "La contraseña es requerida") })
    ),
    defaultValues: {
      username: user?.username || "",
      firstName: user?.firstName || "",
      lastName: user?.lastName || "",
      email: user?.email || "",
      role: (user?.role as any) || "user",
      costCenter: user?.costCenter || "sin_asignar",
      isActive: user?.isActive !== false,
      password: "",
    },
  });

  const mutation = useMutation({
    mutationFn: async (data: UserFormData) => {
      const payload = { ...data };

      // Si estamos editando y no hay contraseña, la omitimos
      if (user && !data.password) {
        delete payload.password;
      }

      if (user) {
        return apiRequest(`/api/users/${user.id}`, {
          method: "PUT",
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(payload),
        });
      } else {
        return apiRequest("/api/users", {
          method: "POST",
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(payload),
        });
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/users"] });
      toast({
        title: "Éxito",
        description: user ? "Usuario actualizado correctamente" : "Usuario creado correctamente",
      });
      onSuccess?.();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Ocurrió un error al procesar el usuario",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: UserFormData) => {
    mutation.mutate(data);
  };

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <FormField
            control={form.control}
            name="username"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Nombre de Usuario</FormLabel>
                <FormControl>
                  <Input {...field} placeholder="Ingrese el nombre de usuario" />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="password"
            render={({ field }) => (
              <FormItem>
                <FormLabel>
                  {user ? "Nueva Contraseña (opcional)" : "Contraseña"}
                </FormLabel>
                <FormControl>
                  <Input 
                    {...field} 
                    type="password" 
                    placeholder={user ? "Dejar vacío para mantener actual" : "Ingrese la contraseña"} 
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="firstName"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Nombre</FormLabel>
                <FormControl>
                  <Input {...field} placeholder="Ingrese el nombre" />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="lastName"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Apellido</FormLabel>
                <FormControl>
                  <Input {...field} placeholder="Ingrese el apellido" />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Email</FormLabel>
                <FormControl>
                  <Input {...field} type="email" placeholder="Ingrese el email" />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="role"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Rol</FormLabel>
                <Select onValueChange={field.onChange} defaultValue={field.value}>
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Seleccione un rol" />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    <SelectItem value="user">Usuario</SelectItem>
                    <SelectItem value="warehouse_operator">Operador de Bodega</SelectItem>
                    <SelectItem value="project_manager">Jefe de Proyecto</SelectItem>
                    <SelectItem value="admin">Administrador</SelectItem>
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="costCenter"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Centro de Costo</FormLabel>
                <Select onValueChange={field.onChange} defaultValue={field.value}>
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Seleccione un centro de costo" />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    <SelectItem value="sin_asignar">Sin asignar</SelectItem>
                    {costCenters.map((center) => (
                      <SelectItem key={center} value={center}>
                        {center}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="isActive"
            render={({ field }) => (
              <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                <div className="space-y-0.5">
                  <FormLabel className="text-base">Estado Activo</FormLabel>
                  <div className="text-sm text-muted-foreground">
                    El usuario puede acceder al sistema
                  </div>
                </div>
                <FormControl>
                  <Switch
                    checked={field.value}
                    onCheckedChange={field.onChange}
                  />
                </FormControl>
              </FormItem>
            )}
          />
        </div>

        <div className="flex justify-end space-x-2">
          <Button type="button" variant="outline" onClick={onCancel}>
            Cancelar
          </Button>
          <Button type="submit" disabled={mutation.isPending}>
            {mutation.isPending ? "Guardando..." : user ? "Actualizar" : "Crear"}
          </Button>
        </div>
      </form>
    </Form>
  );
}

client/src/components/forms/StockEntryFo.content:
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { warehouseEntrySchema, type Product } from "@shared/schema";
import BarcodeScannerNative from "@/components/ui/barcode-scanner-native";
import ProductNotFoundModal from "@/components/modals/ProductNotFoundModal";
import AssociateProductModal from "@/components/modals/AssociateProductModal";
import NewProductWithBarcodeForm from "@/components/forms/NewProductWithBarcodeForm";
import { useBarcodeFlow } from "@/hooks/useBarcodeFlow";
import { z } from "zod";
import { Plus, X, Scan, Package } from "lucide-react";

type StockEntryData = z.infer<typeof warehouseEntrySchema>;

interface StockEntryFormProps {
  onSuccess?: () => void;
  onCancel?: () => void;
}

export default function StockEntryForm({ onSuccess, onCancel }: StockEntryFormProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [serialNumbers, setSerialNumbers] = useState<string[]>([]);
  const [serialInput, setSerialInput] = useState("");

  // Integración del flujo de códigos de barras
  const barcodeFlow = useBarcodeFlow();

  const { data: products = [] } = useQuery<Product[]>({
    queryKey: ["/api/products"],
  });

  const form = useForm<StockEntryData>({
    resolver: zodResolver(warehouseEntrySchema),
    defaultValues: {
      productId: 0,
      quantity: 1,
      price: 0,
      serialNumbers: [],
      reason: "",
    },
  });

  const selectedProductId = form.watch("productId");
  const quantity = form.watch("quantity");

  const selectedProduct = products.find(p => p.id === selectedProductId);
  const requiresSerial = selectedProduct?.requiresSerial || false;

  const stockEntryMutation = useMutation({
    mutationFn: async (data: StockEntryData) => {
      const response = await apiRequest("POST", "/api/stock-entry", {
        ...data,
        serialNumbers: requiresSerial ? serialNumbers : undefined,
        barcodeScanned: barcodeFlow.barcode || undefined,
      });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/inventory"] });
      queryClient.invalidateQueries({ queryKey: ["/api/inventory-movements"] });
      queryClient.invalidateQueries({ queryKey: ["/api/dashboard/metrics"] });
      toast({
        title: "Stock ingresado",
        description: "El stock se ha ingresado exitosamente a la bodega principal.",
      });
      onSuccess?.();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "No se pudo ingresar el stock. Intenta nuevamente.",
        variant: "destructive",
      });
    },
  });

  // Manejadores del flujo de códigos de barras
  const handleBarcodeScanned = (barcode: string) => {
    console.log("🎯 Formulario recibió código:", barcode);
    barcodeFlow.handleBarcodeScanned(barcode);
  };

  const handleProductFound = (product: Product) => {
    // Seleccionar automáticamente el producto en el formulario
    form.setValue("productId", product.id);
    toast({
      title: "Producto encontrado",
      description: `${product.name} - SKU: ${product.sku}`,
    });
    barcodeFlow.reset();
  };

  const handleCreateNewProduct = () => {
    barcodeFlow.handleCreateNew();
  };

  const handleAssociateProduct = () => {
    barcodeFlow.handleAssociateExisting();
  };

  const handleProductCreatedOrAssociated = (product: Product) => {
    handleProductFound(product);
    // Invalidar consultas para refrescar la lista de productos
    queryClient.invalidateQueries({ queryKey: ["/api/products"] });
  };

  // Efecto para manejar automáticamente cuando se encuentra un producto
  useEffect(() => {
    if (barcodeFlow.state === "product-found" && barcodeFlow.product) {
      handleProductFound(barcodeFlow.product);
    }
  }, [barcodeFlow.state, barcodeFlow.product]);

  const addSerialNumber = () => {
    if (serialInput.trim() && !serialNumbers.includes(serialInput.trim())) {
      setSerialNumbers([...serialNumbers, serialInput.trim()]);
      setSerialInput("");
    }
  };

  const removeSerialNumber = (index: number) => {
    setSerialNumbers(serialNumbers.filter((_, i) => i !== index));
  };

  const onSubmit = async (data: StockEntryData) => {
    // Validate serial numbers if required
    if (requiresSerial && serialNumbers.length !== quantity) {
      toast({
        title: "Error de validación",
        description: `Este producto requiere números de serie. Debes agregar exactamente ${quantity} números de serie.`,
        variant: "destructive",
      });
      return;
    }

    await stockEntryMutation.mutateAsync(data);
  };

  return (
    <>
      <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
        <div className="space-y-2">
          <h3 className="text-lg font-semibold">Ingreso de Stock Inicial</h3>
          <p className="text-sm text-muted-foreground">
            El stock se ingresará automáticamente a la bodega principal del centro de costos.
          </p>
        </div>

        <FormField
          control={form.control}
          name="productId"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Producto</FormLabel>
              <div className="space-y-2">
                <div className="flex gap-2">
                  <Select
                    onValueChange={(value) => {
                      field.onChange(parseInt(value));
                      // Reset serial numbers when product changes
                      setSerialNumbers([]);
                    }}
                    value={field.value?.toString()}
                  >
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Seleccionar producto" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      {products.map((product) => (
                        <SelectItem key={product.id} value={product.id.toString()}>
                          <div className="flex items-center gap-2">
                            <span>{product.name}</span>
                            <Badge variant="outline" className="text-xs">
                              {product.sku}
                            </Badge>
                            {product.requiresSerial && (
                              <Badge variant="secondary" className="text-xs">
                                Requiere Serie
                              </Badge>
                            )}
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    onClick={barcodeFlow.startScanning}
                    className="shrink-0"
                    title="Escanear código de barras"
                  >
                    <Scan className="w-4 h-4" />
                  </Button>
                </div>

                {/* Estado del flujo de códigos de barras */}
                {barcodeFlow.barcode && (
                  <div className="p-3 bg-muted rounded-lg">
                    <div className="flex items-center gap-2 text-sm">
                      <Package className="w-4 h-4" />
                      <span className="text-muted-foreground">Código:</span>
                      <span className="font-mono font-semibold">{barcodeFlow.barcode}</span>
                      {barcodeFlow.state === "searching" && (
                        <span className="text-muted-foreground">Buscando...</span>
                      )}
                      {barcodeFlow.product && (
                        <span className="text-green-600">✓ {barcodeFlow.product.name}</span>
                      )}
                    </div>
                  </div>
                )}
              </div>
              <FormMessage />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="quantity"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Cantidad</FormLabel>
              <FormControl>
                <Input
                  type="number"
                  min="1"
                  step="1"
                  placeholder="1"
                  inputMode="numeric"
                  pattern="[0-9]*"
                  {...field}
                  value={field.value || ""}
                  onChange={(e) => {
                    const value = e.target.value;
                    // Permitir campo vacío temporalmente para mejor UX en móviles
                    if (value === "") {
                      field.onChange("");
                      setSerialNumbers([]);
                      return;
                    }

                    // Validar que sea un número positivo
                    const numValue = Number(value);
                    if (!isNaN(numValue) && numValue > 0 && Number.isInteger(numValue)) {
                      field.onChange(numValue);
                      setSerialNumbers([]);
                    }
                  }}
                  onBlur={(e) => {
                    // Si el campo está vacío al salir, establecer valor mínimo
                    if (!e.target.value || Number(e.target.value) < 1) {
                      field.onChange(1);
                    }
                  }}
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="price"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Precio (CLP) *</FormLabel>
              <FormControl>
                <Input
                  type="number"
                  min="0.01"
                  step="0.01"
                  placeholder="0.00"
                  inputMode="decimal"
                  pattern="[0-9]*[.,]?[0-9]*"
                  {...field}
                  value={field.value || ""}
                  onChange={(e) => {
                    const value = e.target.value;
                    if (value === "") {
                      field.onChange("");
                      return;
                    }

                    const numValue = Number(value);
                    if (!isNaN(numValue) && numValue >= 0) {
                      field.onChange(numValue);
                    }
                  }}
                  onBlur={(e) => {
                    if (!e.target.value || Number(e.target.value) <= 0) {
                      field.onChange(0.01);
                    }
                  }}
                />
              </FormControl>
              <FormDescription>
                Precio unitario en pesos chilenos para este ingreso
              </FormDescription>
              <FormMessage />
            </FormItem>
          )}
        />

        {requiresSerial && selectedProductId > 0 && (
          <div className="space-y-2">
            <FormLabel>Números de Serie</FormLabel>
            <FormDescription>
              Este producto requiere números de serie. Agrega {quantity} números únicos.
            </FormDescription>

            <div className="flex gap-2">
              <Input
                placeholder="Ingresa número de serie"
                value={serialInput}
                onChange={(e) => setSerialInput(e.target.value)}
                onKeyPress={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    addSerialNumber();
                  }
                }}
              />
              <Button
                type="button"
                variant="outline"
                size="icon"
                onClick={addSerialNumber}
                disabled={!serialInput.trim() || serialNumbers.length >= quantity}
              >
                <Plus className="w-4 h-4" />
              </Button>
            </div>

            {serialNumbers.length > 0 && (
              <div className="space-y-2">
                <div className="flex flex-wrap gap-2">
                  {serialNumbers.map((serial, index) => (
                    <Badge key={index} variant="outline" className="flex items-center gap-1">
                      {serial}
                      <X
                        className="w-3 h-3 cursor-pointer hover:text-destructive"
                        onClick={() => removeSerialNumber(index)}
                      />
                    </Badge>
                  ))}
                </div>
                <p className="text-sm text-muted-foreground">
                  {serialNumbers.length} de {quantity} números de serie agregados
                </p>
              </div>
            )}
          </div>
        )}

        <FormField
          control={form.control}
          name="reason"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Motivo (Opcional)</FormLabel>
              <FormControl>
                <Textarea placeholder="Descripción del ingreso de stock" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <div className="flex justify-end space-x-3 pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={onCancel}
            disabled={stockEntryMutation.isPending}
          >
            Cancelar
          </Button>
          <Button
            type="submit"
            disabled={stockEntryMutation.isPending}
          >
            {stockEntryMutation.isPending ? "Ingresando..." : "Ingresar Stock"}
          </Button>
        </div>
      </form>
    </Form>

      {/* Escáner de códigos de barras */}
      <BarcodeScannerNative
        isOpen={barcodeFlow.state === "scanning"}
        onClose={barcodeFlow.handleCancel}
        onScan={handleBarcodeScanned}
        title="Escanear Producto"
        description="Apunta la cámara hacia el código de barras del producto"
      />

      {/* Modal cuando no se encuentra el producto */}
      <ProductNotFoundModal
        isOpen={barcodeFlow.state === "product-not-found"}
        onClose={barcodeFlow.handleCancel}
        barcode={barcodeFlow.barcode || ""}
        onCreateNew={handleCreateNewProduct}
        onAssociateExisting={handleAssociateProduct}
      />

      {/* Modal para crear nuevo producto */}
      <NewProductWithBarcodeForm
        isOpen={barcodeFlow.state === "creating-new"}
        onClose={barcodeFlow.handleCancel}
        barcode={barcodeFlow.barcode || ""}
        onSuccess={handleProductCreatedOrAssociated}
      />

      {/* Modal para asociar producto existente */}
      <AssociateProductModal
        isOpen={barcodeFlow.state === "associating-existing"}
        onClose={barcodeFlow.handleCancel}
        barcode={barcodeFlow.barcode || ""}
        onSuccess={handleProductCreatedOrAssociated}
      />
    </>
  );
}

