import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQueryClient, useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { insertWarehouseSchema, type Warehouse } from "@shared/schema";
import { z } from "zod";

type WarehouseFormData = z.infer<typeof insertWarehouseSchema>;

interface WarehouseFormProps {
  onSuccess?: () => void;
}

const costCenterFormSchema = z.object({
  costCenter: z.string().min(1, "Centro de costos es requerido"),
  location: z.string().optional(),
});

type CostCenterFormData = z.infer<typeof costCenterFormSchema>;

export default function WarehouseForm({ onSuccess }: WarehouseFormProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isCreatingCostCenter, setIsCreatingCostCenter] = useState(false);

  // Obtener lista de bodegas para la selección de bodega padre
  const { data: warehouses } = useQuery<Warehouse[]>({
    queryKey: ["/api/warehouses"],
  });

  const form = useForm<WarehouseFormData>({
    resolver: zodResolver(insertWarehouseSchema),
    defaultValues: {
      name: "",
      location: "",
      costCenter: "",
      parentWarehouseId: undefined,
      warehouseType: "sub",
      isActive: true,
    },
  });

  const createWarehouseMutation = useMutation({
    mutationFn: async (data: WarehouseFormData) => {
      const response = await apiRequest("POST", "/api/warehouses", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/warehouses"] });
      queryClient.invalidateQueries({ queryKey: ["/api/dashboard/metrics"] });
      toast({
        title: "Bodega creada",
        description: "La bodega se ha creado exitosamente.",
      });
      onSuccess?.();
    },
    onError: () => {
      toast({
        title: "Error",
        description: "No se pudo crear la bodega. Intenta nuevamente.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: WarehouseFormData) => {
    createWarehouseMutation.mutate(data);
  };

  return (
    <>
      <DialogHeader>
        <DialogTitle>Nueva Bodega</DialogTitle>
      </DialogHeader>

      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
          <FormField
            control={form.control}
            name="name"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Nombre de la Bodega</FormLabel>
                <FormControl>
                  <Input placeholder="Ej. Bodega Central" {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="location"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Ubicación</FormLabel>
                <FormControl>
                  <Textarea placeholder="Dirección de la bodega" {...field} value={field.value || ""} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="costCenter"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Centro de Costos</FormLabel>
                <FormControl>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecciona el centro de costos" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="PRINCIPAL">PRINCIPAL</SelectItem>
                      <SelectItem value="UM2">UM2</SelectItem>
                      <SelectItem value="PLATAFORMA">PLATAFORMA</SelectItem>
                      <SelectItem value="PEM">PEM</SelectItem>
                      <SelectItem value="INTEGRADOR">INTEGRADOR</SelectItem>
                    </SelectContent>
                  </Select>
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="warehouseType"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Tipo de Bodega</FormLabel>
                <FormControl>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecciona el tipo" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="main">Bodega Principal</SelectItem>
                      <SelectItem value="sub">Sub-bodega</SelectItem>
                    </SelectContent>
                  </Select>
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="parentWarehouseId"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Bodega Padre (opcional)</FormLabel>
                <FormControl>
                  <Select 
                    onValueChange={(value) => field.onChange(value ? parseInt(value) : undefined)} 
                    value={field.value?.toString() || ""}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecciona bodega padre" />
                    </SelectTrigger>
                    <SelectContent>
                      {warehouses?.filter(w => w.warehouseType === 'main').map((warehouse) => (
                        <SelectItem key={warehouse.id} value={warehouse.id.toString()}>
                          {warehouse.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <div className="flex justify-end space-x-3 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => onSuccess?.()}
              disabled={createWarehouseMutation.isPending}
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={createWarehouseMutation.isPending}
            >
              {createWarehouseMutation.isPending ? "Creando..." : "Crear Bodega"}
            </Button>
          </div>
        </form>
      </Form>
    </>
  );
}

client/src/components/forms/SimpleProduc.content:
import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQueryClient, useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { type Unit, type Category, type Brand } from "@shared/schema";
import { z } from "zod";

// Esquema personalizado para el formulario
const productFormSchema = z.object({
  name: z.string().min(1, "El nombre es requerido"),
  sku: z.string().optional(),
  barcode: z.string().optional(),
  description: z.string().optional(),
  productType: z.enum(["tangible", "intangible"]).default("tangible"),
  requiresSerial: z.boolean().default(false),
  isActive: z.boolean().default(true),
  unitId: z.number().min(1, "Debe seleccionar una unidad"),
  categoryId: z.number().min(1, "Debe seleccionar una categoría"),
  brandId: z.number().min(1, "Debe seleccionar una marca"),
  hasWarranty: z.boolean().default(false),
  warrantyMonths: z.number().min(0, "La garantía debe ser mayor o igual a 0").default(0),
  currentPrice: z.number().min(0, "El precio debe ser mayor a 0"),
});

type ProductFormData = z.infer<typeof productFormSchema>;

interface SimpleProductFormProps {
  onSuccess?: () => void;
  onCancel?: () => void;
}

export default function SimpleProductForm({ onSuccess, onCancel }: SimpleProductFormProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Obtener opciones para los selectores
  const { data: units = [] } = useQuery<Unit[]>({
    queryKey: ["/api/units"],
  });

  const { data: categories = [] } = useQuery<Category[]>({
    queryKey: ["/api/categories"],
  });

  const { data: brands = [] } = useQuery<Brand[]>({
    queryKey: ["/api/brands"],
  });

  const form = useForm<ProductFormData>({
    resolver: zodResolver(productFormSchema),
    defaultValues: {
      name: "",
      sku: "",
      barcode: "",
      description: "",
      productType: "tangible",
      requiresSerial: false,
      isActive: true,
      unitId: 0,
      categoryId: 0,
      brandId: 0,
      hasWarranty: false,
      warrantyMonths: 0,
      currentPrice: 0,
    },
  });

  const onSubmit = async (data: ProductFormData) => {
    try {
      setIsSubmitting(true);

      // Separar precio del resto de datos
      const { currentPrice, ...productData } = data;

      // Crear el producto
      const response = await apiRequest("/api/products", {
        method: "POST",
        body: JSON.stringify({
          ...productData,
          currentPrice: currentPrice || 0,
        }),
      });

      if (response.ok) {
        toast({
          title: "Producto creado",
          description: "El producto ha sido creado exitosamente",
        });

        // Invalidar cache
        queryClient.invalidateQueries({ queryKey: ["/api/products"] });

        // Resetear formulario
        form.reset();

        // Callback de éxito
        onSuccess?.();
      } else {
        throw new Error("Error al crear el producto");
      }
    } catch (error) {
      console.error("Error:", error);
      toast({
        title: "Error",
        description: "No se pudo crear el producto. Intente nuevamente.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 pb-16">
        {/* Nombre del Producto */}
        <FormField
          control={form.control}
          name="name"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Nombre del Producto *</FormLabel>
              <FormControl>
                <Input {...field} placeholder="Ingrese el nombre del producto" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* SKU */}
        <FormField
          control={form.control}
          name="sku"
          render={({ field }) => (
            <FormItem>
              <FormLabel>SKU</FormLabel>
              <FormControl>
                <Input {...field} value={field.value || ""} placeholder="Código SKU del producto" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Código de Barras */}
        <FormField
          control={form.control}
          name="barcode"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Código de Barras</FormLabel>
              <FormControl>
                <Input {...field} value={field.value || ""} placeholder="Ej: 1234567890123" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Descripción */}
        <FormField
          control={form.control}
          name="description"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Descripción</FormLabel>
              <FormControl>
                <Textarea {...field} value={field.value || ""} placeholder="Descripción del producto" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Categoría */}
        <FormField
          control={form.control}
          name="categoryId"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Categoría *</FormLabel>
              <Select onValueChange={(value) => field.onChange(parseInt(value))} value={field.value?.toString()}>
                <FormControl>
                  <SelectTrigger>
                    <SelectValue placeholder="Seleccione una categoría" />
                  </SelectTrigger>
                </FormControl>
                <SelectContent>
                  {categories.map((category) => (
                    <SelectItem key={category.id} value={category.id.toString()}>
                      {category.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Marca */}
        <FormField
          control={form.control}
          name="brandId"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Marca *</FormLabel>
              <Select onValueChange={(value) => field.onChange(parseInt(value))} value={field.value?.toString()}>
                <FormControl>
                  <SelectTrigger>
                    <SelectValue placeholder="Seleccione una marca" />
                  </SelectTrigger>
                </FormControl>
                <SelectContent>
                  {brands.map((brand) => (
                    <SelectItem key={brand.id} value={brand.id.toString()}>
                      {brand.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Unidad de Medida */}
        <FormField
          control={form.control}
          name="unitId"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Unidad de Medida *</FormLabel>
              <Select onValueChange={(value) => field.onChange(parseInt(value))} value={field.value?.toString()}>
                <FormControl>
                  <SelectTrigger>
                    <SelectValue placeholder="Seleccione una unidad" />
                  </SelectTrigger>
                </FormControl>
                <SelectContent>
                  {units.map((unit) => (
                    <SelectItem key={unit.id} value={unit.id.toString()}>
                      {unit.name} ({unit.abbreviation})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Precio Actual */}
        <FormField
          control={form.control}
          name="currentPrice"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Precio Actual (CLP) *</FormLabel>
              <FormControl>
                <Input 
                  type="number" 
                  {...field} 
                  value={field.value || 0}
                  onChange={(e) => field.onChange(parseFloat(e.target.value) || 0)}
                  placeholder="0" 
                  min="0"
                  step="0.01"
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Garantía */}
        <FormField
          control={form.control}
          name="hasWarranty"
          render={({ field }) => (
            <FormItem className="flex flex-row items-start space-x-3 space-y-0 rounded-md border p-4">
              <FormControl>
                <Switch
                  checked={field.value}
                  onCheckedChange={field.onChange}
                />
              </FormControl>
              <div className="space-y-1 leading-none">
                <FormLabel>
                  Tiene Garantía
                </FormLabel>
                <p className="text-sm text-muted-foreground">
                  Activar si el producto incluye garantía
                </p>
              </div>
            </FormItem>
          )}
        />

        {/* Meses de Garantía - Solo si tiene garantía */}
        {form.watch("hasWarranty") && (
          <FormField
            control={form.control}
            name="warrantyMonths"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Meses de Garantía *</FormLabel>
                <FormControl>
                  <Input 
                    type="number" 
                    {...field} 
                    value={field.value || 0}
                    onChange={(e) => field.onChange(parseInt(e.target.value) || 0)}
                    placeholder="Ej: 12, 24, 36" 
                    min="1"
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
        )}

        {/* Tipo de Producto */}
        <FormField
          control={form.control}
          name="productType"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Tipo de Producto</FormLabel>
              <Select onValueChange={field.onChange} value={field.value}>
                <FormControl>
                  <SelectTrigger>
                    <SelectValue placeholder="Seleccione el tipo" />
                  </SelectTrigger>
                </FormControl>
                <SelectContent>
                  <SelectItem value="tangible">Tangible</SelectItem>
                  <SelectItem value="intangible">Intangible</SelectItem>
                </SelectContent>
              </Select>
              <FormMessage />
            </FormItem>
          )}
        />

        {/* Requiere Número de Serie */}
        <FormField
          control={form.control}
          name="requiresSerial"
          render={({ field }) => (
            <FormItem className="flex flex-row items-start space-x-3 space-y-0 rounded-md border p-4">
              <FormControl>
                <Switch
                  checked={field.value}
                  onCheckedChange={field.onChange}
                />
              </FormControl>
              <div className="space-y-1 leading-none">
                <FormLabel>
                  Requiere Número de Serie
                </FormLabel>
                <p className="text-sm text-muted-foreground">
                  Activar si el producto necesita números de serie únicos
                </p>
              </div>
            </FormItem>
          )}
        />

        {/* Producto Activo */}
        <FormField
          control={form.control}
          name="isActive"
          render={({ field }) => (
            <FormItem className="flex flex-row items-start space-x-3 space-y-0 rounded-md border p-4">
              <FormControl>
                <Switch
                  checked={field.value}
                  onCheckedChange={field.onChange}
                />
              </FormControl>
              <div className="space-y-1 leading-none">
                <FormLabel>
                  Producto Activo
                </FormLabel>
                <p className="text-sm text-muted-foreground">
                  Desactivar para ocultar el producto del sistema
                </p>
              </div>
            </FormItem>
          )}
        />

        {/* Botones */}
        <div className="flex justify-end space-x-2">
          {onCancel && (
            <Button type="button" variant="outline" onClick={onCancel}>
              Cancelar
            </Button>
          )}
          <Button type="submit" disabled={isSubmitting}>
            {isSubmitting ? "Creando..." : "Crear Producto"}
          </Button>
        </div>
      </form>
    </Form>
  );
}

