            <Tags className="h-4 w-4" />
            Categorías
          </TabsTrigger>
          <TabsTrigger value="brands" className="flex items-center gap-2">
            <Award className="h-4 w-4" />
            Marcas
          </TabsTrigger>
          <TabsTrigger value="units" className="flex items-center gap-2">
            <Ruler className="h-4 w-4" />
            Unidades
          </TabsTrigger>
        </TabsList>

        <TabsContent value="products" className="space-y-6">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold">Lista de Productos</h2>
              <p className="text-muted-foreground">
                Administre el catálogo de productos y precios mensuales
              </p>
            </div>
            <Dialog open={isCreateDialogOpen} onOpenChange={setIsCreateDialogOpen}>
              <DialogTrigger asChild>
                <Button>
                  <Plus className="h-4 w-4 mr-2" />
                  Nuevo Producto
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                  <DialogTitle>Crear Nuevo Producto</DialogTitle>
                  <DialogDescription>
                    Complete los detalles del nuevo producto. Todos los campos marcados con * son obligatorios.
                  </DialogDescription>
                </DialogHeader>
                <SimpleProductForm onSuccess={handleCreateProduct} />
              </DialogContent>
            </Dialog>
          </div>

          {isLoading ? (
            <div className="grid gap-4">
              {[1, 2, 3].map((i) => (
                <div key={i} className="h-24 bg-muted animate-pulse rounded-lg"></div>
              ))}
            </div>
          ) : (
            <div className="grid gap-4">
              {products.map((product) => (
                <Card key={product.id} className="hover:shadow-md transition-shadow">
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <div className="space-y-1">
                      <CardTitle className="text-lg flex items-center gap-2">
                        <Package className="h-5 w-5" />
                        {product.name}
                      </CardTitle>
                      <CardDescription className="flex items-center gap-4">
                        <span className="flex items-center gap-1">
                          <strong>SKU:</strong> {product.sku || "Sin SKU"}
                        </span>
                        {product.barcode && (
                          <span className="flex items-center gap-1">
                            <strong>Código:</strong> {product.barcode}
                          </span>
                        )}
                      </CardDescription>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge variant={getProductTypeBadge(product.productType || "tangible") as any}>
                        {getProductTypeLabel(product.productType || "tangible")}
                      </Badge>
                      {product.requiresSerial && (
                        <Badge variant="outline">Requiere N° Serie</Badge>
                      )}
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center justify-between">
                      <div className="space-y-1">
                        <p className="text-sm text-muted-foreground">
                          {product.description || "Sin descripción"}
                        </p>
                        <div className="flex items-center gap-4 text-sm">
                          <span className="flex items-center gap-1">
                            <strong>Precio Actual:</strong> {formatPrice(product.currentPrice?.price)}
                          </span>
                          <span className="flex items-center gap-1">
                            <strong>Estado:</strong> {product.isActive ? "Activo" : "Inactivo"}
                          </span>
                        </div>
                      </div>
                      <Button 
                        variant="outline" 
                        size="sm"
                        onClick={() => handleEditProduct(product)}
                      >
                        Editar
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="categories">
          <CategoryManagement />
        </TabsContent>

        <TabsContent value="brands">
          <BrandManagement />
        </TabsContent>

        <TabsContent value="units">
          <UnitManagement />
        </TabsContent>
      </Tabs>

      {/* Diálogo de Edición */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Editar Producto</DialogTitle>
            <DialogDescription>
              Modifique los detalles del producto. Todos los campos marcados con * son obligatorios.
            </DialogDescription>
          </DialogHeader>
          {selectedProduct && (
            <EditProductForm 
              product={selectedProduct}
              onSuccess={handleEditSuccess}
              onCancel={() => setIsEditDialogOpen(false)}
            />
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

